if value is None or value == '':
	return 'No Line Selected'
return str(value)

try:
    lineId = value
    if lineId is None:
        return ''
    total = system.db.runPrepQuery('SELECT COUNT(*) FROM productcode WHERE disable = false', [], 'mes_core').getValueAt(0, 0)
    assigned = system.db.runPrepQuery('SELECT COUNT(*) FROM productcodeline WHERE lineid = ? AND enable = true', [int(lineId)], 'mes_core').getValueAt(0, 0)
    return str(assigned) + ' of ' + str(total) + ' products assigned'
except:
    return ''

dbName = "mes_core"
query = "SELECT id AS \"ID\", productcode AS \"ProductCode\", description AS \"Description\", disable AS \"Disable\", \"TimeStamp\" FROM productcode ORDER BY productcode"
try:
    data = system.db.runPrepQuery(query, [], dbName)
    if data.getRowCount() > 0:
        column_names = data.getColumnNames()
        json_data = system.dataset.toPyDataSet(data)
        return [{ col: row[col] for col in column_names } for row in json_data]
    else:
        return []
except Exception as e:
    system.util.getLogger('DataConfig').error('Query failed: {}'.format(str(e)))
    return []

