config.script:
logger = system.util.getLogger('DataConfig')
form = self.parent.parent
productId = form.getChild('productField').getChild('productDropdown').props.value
lineId = self.view.custom.selectedLineId
if productId is None or lineId is None:
	return
try:
	exists = system.db.runPrepQuery('SELECT id FROM productcodeline WHERE productcodeid = ? AND lineid = ?', [productId, lineId], 'mes_core')
	if exists.getRowCount() > 0:
		system.db.runPrepUpdate('UPDATE productcodeline SET enable = true, "TimeStamp" = NOW() WHERE productcodeid = ? AND lineid = ?', [productId, lineId], 'mes_core')
	else:
		system.db.runPrepUpdate('INSERT INTO productcodeline (productcodeid, lineid, enable, "TimeStamp") VALUES (?, ?, true, NOW())', [productId, lineId], 'mes_core')
	self.view.custom.showAssignProduct = False
	form.parent.getChild('lineProductCodesTable').refreshBinding('props.data')
except Exception as e:
	logger.error('Assign failed: {}'.format(str(e)))
